        # Replace with the actual namespaces used in your SOAP requests.
        namespaces = [
          soap: "http://schemas.xmlsoap.org/soap/envelope/",
          m: "http://example.com/myservice/messages" # Example custom service namespace
        ]

        # Example: Extract a username from a SOAP request body using xpath.
        # Assuming an XML structure like:
        # <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/"
        #                xmlns:m="http://example.com/myservice/messages">
        #   <soap:Body>
        #     <m:GetUserRequest>
        #       <m:Username>johndoe</m:Username>
        #       <m:Password>secret</m:Password>
        #     </m:GetUserRequest>
