        # </soap:Envelope>

        # SweetXml.xpath/3 expects namespaces as a keyword list or a list of tuples.
        ns_list = Keyword.new(namespaces)

        # Use `~s` for string XPath query. It's often simpler for direct extractions.
        username = xml_doc |> SweetXml.xpath(~s"//m:GetUserRequest/m:Username/text()", ns_list)

