          <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
            <soap:Body>
              <m:GetUserResponse xmlns:m="http://example.com/myservice/messages">
                <m:UserID>user-#{username}</m:UserID>
                <m:Status>Success</m:Status>
              </m:GetUserResponse>
            </soap:Body>
          </soap:Envelope>
          """
          conn
          |> put_resp_content_type("application/soap+xml; charset=utf-8")
          |> send_resp(200, response_xml)
        else
